using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests
{
    private SchoolContext CreateContextWithStudents()
    {
        var context = TestDbContextFactory.Create();
        context.Students.AddRange(
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) },
            new Student { ID = 4, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) }
        );
        context.SaveChanges();
        return context;
    }

    [Fact]
    public void Index_ReturnsViewResult_WithPaginatedList()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(4, model.Count);
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudents()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Alexander", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_WithNameDescSort_OrdersByLastNameDescending()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Barzdukas", model[0].LastName);
    }

    [Fact]
    public void Index_WithDateSort_OrdersByEnrollmentDate()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_WithDateDescSort_OrdersByEnrollmentDateDescending()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_SearchStringResetsPage()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Al", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(2, model.Count); // Alexander and Alonso
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Index(null, "Alexander", null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Details_WithValidId_ReturnsStudent()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new StudentsController(context);

        var result = controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new StudentsController(context);
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Create(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Single(context.Students);
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_ReturnsView()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new StudentsController(context);
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = DateTime.MinValue
        };

        var result = controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new StudentsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Create(student);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsStudent()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);
        var student = new Student
        {
            ID = 1,
            LastName = "Updated",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };
        // Detach the tracked entity
        var tracked = context.Students.Find(1);
        context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = controller.Edit(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);
        var student = new Student
        {
            ID = 1,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.MinValue
        };

        var result = controller.Edit(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(controller.ModelState.IsValid);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsStudent()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
    {
        using var context = CreateContextWithStudents();
        var controller = new StudentsController(context);

        var result = controller.DeleteConfirmed(1);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(3, context.Students.Count());
    }
}

