using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests
{
    private SchoolContext CreateContextWithDepartments()
    {
        var context = TestDbContextFactory.Create();
        var instructor = new Instructor { ID = 1, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = new DateTime(2002, 7, 6) };
        context.Instructors.Add(instructor);
        context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = 1 },
            new Department { DepartmentID = 2, Name = "English", Budget = 100000, StartDate = new DateTime(2007, 9, 1) },
            new Department { DepartmentID = 3, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1) }
        );
        context.SaveChanges();
        return context;
    }

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Details_WithValidId_ReturnsDepartment()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Create_Get_ReturnsView()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Create();

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = new DateTime(2023, 9, 1),
            InstructorID = 1
        };

        var result = controller.Create(department);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(4, context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { Budget = 200000, StartDate = DateTime.Now };

        var result = controller.Create(department);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsDepartment()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);
        var tracked = context.Departments.Find(1);
        context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Updated Engineering",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 1
        };

        var result = controller.Edit(department);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1, Budget = 400000, StartDate = DateTime.Now };

        var result = controller.Edit(department);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsDepartment()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
    {
        using var context = CreateContextWithDepartments();
        var controller = new DepartmentsController(context);

        var result = controller.DeleteConfirmed(1);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(2, context.Departments.Count());
    }
}

