using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests
{
    private SchoolContext CreateContextWithInstructors()
    {
        var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Micro", Credits = 3, DepartmentID = 1 }
        );
        context.Instructors.AddRange(
            new Instructor
            {
                ID = 1, LastName = "Abercrombie", FirstMidName = "Kim", HireDate = new DateTime(1995, 3, 11),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            },
            new Instructor
            {
                ID = 2, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = new DateTime(2002, 7, 6),
                CourseAssignments = new List<CourseAssignment>()
            }
        );
        context.SaveChanges();
        // Add course assignments after saving
        context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1050 });
        context.SaveChanges();
        return context;
    }

    [Fact]
    public void Index_NoParams_ReturnsAllInstructors()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ShowsCourses()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Index(1, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Details_WithValidId_ReturnsInstructor()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Create_Get_ReturnsView()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = controller.Create(instructor, null);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "1050", "4022" };

        var result = controller.Create(instructor, selectedCourses);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(2, instructor.CourseAssignments.Count);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = controller.Create(instructor, null);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsInstructor()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
    {
        using var context = CreateContextWithInstructors();
        var controller = new InstructorsController(context);

        var result = controller.DeleteConfirmed(1);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Single(context.Instructors);
    }

    [Fact]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        using var context = CreateContextWithInstructors();
        // Set instructor 1 as department admin
        var dept = context.Departments.Find(1);
        dept.InstructorID = 1;
        context.SaveChanges();

        var controller = new InstructorsController(context);
        controller.DeleteConfirmed(1);

        var updatedDept = context.Departments.Find(1);
        Assert.Null(updatedDept.InstructorID);
    }
}

