using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        using var context = TestDbContextFactory.Create();
        var student = new Student { LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Now };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.Equal("Test", retrieved.LastName);
        Assert.Equal("Student", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "Test", Budget = 100, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        var course = new Course { CourseID = 100, Title = "TestCourse", Credits = 3, DepartmentID = 1 };

        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.First();
        Assert.Equal("TestCourse", retrieved.Title);
        Assert.Equal(3, retrieved.Credits);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        using var context = TestDbContextFactory.Create();
        var department = new Department { Name = "Science", Budget = 200000, StartDate = new DateTime(2020, 1, 1) };

        context.Departments.Add(department);
        context.SaveChanges();

        var retrieved = context.Departments.First();
        Assert.Equal("Science", retrieved.Name);
        Assert.Equal(200000, retrieved.Budget);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor { LastName = "Smith", FirstMidName = "John", HireDate = new DateTime(2020, 1, 1) };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First();
        Assert.Equal("Smith", retrieved.LastName);
    }

    [Fact]
    public void CanAddEnrollment()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "D", Budget = 0, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        var student = new Student { ID = 1, LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Now };
        var course = new Course { CourseID = 100, Title = "C", Credits = 3, DepartmentID = 1 };
        context.Students.Add(student);
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment { StudentID = 1, CourseID = 100, Grade = Grade.A };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.First();
        Assert.Equal(Grade.A, retrieved.Grade);
        Assert.Equal(1, retrieved.StudentID);
        Assert.Equal(100, retrieved.CourseID);
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "D", Budget = 0, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        var instructor = new Instructor { ID = 1, LastName = "I", FirstMidName = "T", HireDate = DateTime.Now };
        var course = new Course { CourseID = 100, Title = "C", Credits = 3, DepartmentID = 1 };
        context.Instructors.Add(instructor);
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment { InstructorID = 1, CourseID = 100 };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.Find(100, 1);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void OfficeAssignment_HasInstructorKey()
    {
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor { ID = 1, LastName = "I", FirstMidName = "T", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
        context.OfficeAssignments.Add(office);
        context.SaveChanges();

        var retrieved = context.OfficeAssignments.Find(1);
        Assert.NotNull(retrieved);
        Assert.Equal("Room 101", retrieved.Location);
    }

    [Fact]
    public void Student_InheritsFromPerson()
    {
        using var context = TestDbContextFactory.Create();
        var student = new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Now };
        context.Students.Add(student);
        context.SaveChanges();

        var person = context.People.First();
        Assert.Equal("Doe", person.LastName);
        Assert.Equal("Doe, Jane", person.FullName);
    }

    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor { LastName = "Smith", FirstMidName = "John", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var person = context.People.First();
        Assert.Equal("Smith", person.LastName);
        Assert.Equal("Smith, John", person.FullName);
    }

    [Fact]
    public void CanAddNotification()
    {
        using var context = TestDbContextFactory.Create();
        var notification = new Notification
        {
            EntityType = "Test",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };

        context.Notifications.Add(notification);
        context.SaveChanges();

        var retrieved = context.Notifications.First();
        Assert.Equal("Test", retrieved.EntityType);
        Assert.Equal("Test message", retrieved.Message);
    }

    [Fact]
    public void Course_DepartmentRelationship()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "Science", Budget = 100, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.Courses.Add(new Course { CourseID = 1, Title = "Physics", Credits = 3, DepartmentID = 1 });
        context.SaveChanges();

        var course = context.Courses.Include(c => c.Department).First();
        Assert.NotNull(course.Department);
        Assert.Equal("Science", course.Department.Name);
    }

    [Fact]
    public void Student_EnrollmentRelationship()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department { DepartmentID = 1, Name = "D", Budget = 0, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        var student = new Student { ID = 1, LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Now };
        var course = new Course { CourseID = 1, Title = "C", Credits = 3, DepartmentID = 1 };
        context.Students.Add(student);
        context.Courses.Add(course);
        context.SaveChanges();
        context.Enrollments.Add(new Enrollment { StudentID = 1, CourseID = 1, Grade = Grade.B });
        context.SaveChanges();

        var retrieved = context.Students.Include(s => s.Enrollments).First();
        Assert.Single(retrieved.Enrollments);
        Assert.Equal(Grade.B, retrieved.Enrollments.First().Grade);
    }
}

